// Parse PG outputs (each returns {result: JSON array or string})
function parseResult(x) {
  let r = x?.result;
  if (typeof r === 'string') { try { r = JSON.parse(r); } catch(e) { r = []; } }
  return Array.isArray(r) ? r : [];
}

const rfm = parseResult($('PG: RFM Segments').item.json);
const wk = parseResult($('PG: Weekly Delta').item.json)[0] || {};
const atrisk = parseResult($('PG: At Risk Top').item.json);

const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const d = new Date();
const weekTo = d.toISOString().slice(0,10);
const d7 = new Date(d.getTime() - 7*86400*1000).toISOString().slice(0,10);

// Build RFM section
const totalUsers = rfm.reduce((s,r) => s + Number(r.users||0), 0);
const totalGmv = rfm.reduce((s,r) => s + Number(r.gmv||0), 0);

const emoji = {
  'Champions': '\ud83c\udfc6',
  'Loyal': '\ud83d\udc9a',
  'New/Recent': '\u2728',
  'Cannot Lose': '\u26a0\ufe0f',
  'At Risk': '\ud83d\udd34',
  'Potential': '\ud83c\udf31',
  'Lost': '\u26ab\ufe0f'
};

const rfmLines = rfm.map(r => {
  const em = emoji[r.segment] || '\u25cf';
  const gmvShare = totalGmv > 0 ? Math.round(Number(r.gmv)/totalGmv*100) : 0;
  const nutakuShare = r.users > 0 ? Math.round(Number(r.nutaku_users)/Number(r.users)*100) : 0;
  return em + ' <b>' + r.segment + '</b>: ' + r.users + ' \u044e\u0437\u0435\u0440\u043e\u0432 (' + nutakuShare + '% Nutaku), LTV \u20ac' + r.avg_ltv + ', \u0432\u044b\u0440\u0443\u0447\u043a\u0430 \u20ac' + r.gmv + ' (' + gmvShare + '%)';
}).join('\n');

// Weekly activity
const weeklyLine = '\ud83d\udcca <b>\u041d\u0435\u0434\u0435\u043b\u044f:</b> ' + (wk.active_7d||0) + ' \u0430\u043a\u0442\u0438\u0432\u043d\u044b\u0445 \u043f\u043e\u043a\u0443\u043f\u0430\u0442\u0435\u043b\u0435\u0439 (' + (wk.new_buyers_7d||0) + ' \u043d\u043e\u0432\u044b\u0445, ' + (wk.returning_7d||0) + ' \u0432\u0435\u0440\u043d\u0443\u0432\u0448\u0438\u0445\u0441\u044f), \u20ac' + (wk.gmv_7d_eur||0);

// At Risk list
let atriskBlock = '';
if (atrisk.length > 0) {
  const lines = atrisk.slice(0, 10).map((r, i) => {
    const tg = r.tg ? '\ud83d\udce9' : '\u2063';
    return (i+1) + '. ' + tg + ' <code>' + esc(r.email || '(no email)') + '</code> \u2014 <b>\u20ac' + r.ltv + '</b> LTV, ' + r.orders + ' \u0437\u0430\u043a\u0430\u0437\u043e\u0432, \u043c\u043e\u043b\u0447\u0438\u0442 ' + r.silent + ' \u0434\u043d.';
  }).join('\n');
  atriskBlock = '\n\n\ud83c\udfaf <b>At Risk Champions \u2014 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u044b \u043d\u0430 winback</b>\n' + lines;
}

const text = '\ud83d\udcca <b>RFM Weekly Digest</b>\n<i>' + d7 + ' \u2192 ' + weekTo + '</i>\n\n' + weeklyLine + '\n\n<b>\u0412\u0441\u0435\u0433\u043e \u043f\u043e\u043a\u0443\u043f\u0430\u0442\u0435\u043b\u0435\u0439 \u0432 \u0431\u0430\u0437\u0435:</b> ' + totalUsers + ' \u043d\u0430 \u20ac' + totalGmv + ' LTV\n\n' + rfmLines + atriskBlock;

return [{json: {text, rfm, weekly: wk, atrisk}}];
